   127	static int estimate_ul_buffer_short_bsr(const NR_BSR_SHORT *bsr)
   128	{
   129	  /* NOTE: the short BSR might be for different LCGID than 0, but we do not
   130	   * differentiate them */
   131	  int rep_idx = bsr->Buffer_size;
   132	  int estim_idx = overestim_bsr_index(rep_idx);
   133	  int max = sizeofArray(NR_SHORT_BSR_TABLE) - 1;
   134	  int idx = min(estim_idx, max);
   135	  int estim_size = NR_SHORT_BSR_TABLE[idx];
   136	  LOG_D(NR_MAC, "short BSR LCGID %d index %d estim index %d size %d\n", bsr->LcgID, rep_idx, estim_idx, estim_size);
   137	  return estim_size;
   138	}
