   140	static int estimate_ul_buffer_long_bsr(const NR_BSR_LONG *bsr)
   141	{
   142	  LOG_D(NR_MAC,
   143	        "LONG BSR, LCG ID(7-0) %d/%d/%d/%d/%d/%d/%d/%d\n",
   144	        bsr->LcgID7,
   145	        bsr->LcgID6,
   146	        bsr->LcgID5,
   147	        bsr->LcgID4,
   148	        bsr->LcgID3,
   149	        bsr->LcgID2,
   150	        bsr->LcgID1,
   151	        bsr->LcgID0);
   152	  bool bsr_active[8] = {bsr->LcgID0 != 0, bsr->LcgID1 != 0, bsr->LcgID2 != 0, bsr->LcgID3 != 0, bsr->LcgID4 != 0, bsr->LcgID5 != 0, bsr->LcgID6 != 0, bsr->LcgID7 != 0};
   153	
   154	  int estim_size = 0;
   155	  int max = sizeofArray(NR_LONG_BSR_TABLE) - 1;
   156	  uint8_t *payload = ((uint8_t*) bsr) + 1;
   157	  int m = 0;
   158	  const int total_lcgids = 8; /* see 38.321 6.1.3.1 */
   159	  for (int n = 0; n < total_lcgids; n++) {
   160	    if (!bsr_active[n])
   161	      continue;
   162	    int rep_idx = payload[m];
   163	    int estim_idx = overestim_bsr_index(rep_idx);
   164	    int idx = min(estim_idx, max);
   165	    estim_size += NR_LONG_BSR_TABLE[idx];
   166	
   167	    LOG_D(NR_MAC, "LONG BSR LCGID/m %d/%d Index %d estim index %d size %d", n, m, rep_idx, estim_idx, estim_size);
   168	    m++;
   169	  }
   170	  return estim_size;
   171	}
